import React from 'react';
import './EyePanel.css';

export default function EyePanel() {
  return (
    <div className="eye-panel">
      {/* closed eye — fades out as it opens */}
      <img
        className="eye-img eye-closed-layer"
        src="/eye-closed.svg"
        alt=""
        draggable={false}
      />
      {/* open eye — clip-path expands like a lid lifting */}
      <img
        className="eye-img eye-open-layer"
        src="/eye-open.svg"
        alt=""
        draggable={false}
      />
    </div>
  );
}
